// src/pages/profile.tsx
import type { NextPage } from "next";
import Head from "next/head";
import Image from "next/image";
import { useRouter } from "next/router";
import { signOut, useSession } from "next-auth/react";
import { trpc } from "../utils/trpc";

const Profile: NextPage = () => {
  const router = useRouter();
  const { data: session, status } = useSession();

  // Fetches the GitHub profile through the tRPC context, confirming that
  // session data (id, name, username, image) is properly threaded through
  // the tRPC request context on the server side.
  const { data: profile } = trpc.useQuery(["auth.getProfile"], {
    enabled: !!session,
  });

  if (status === "loading") {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <p className="text-gray-500">Loading...</p>
      </div>
    );
  }

  if (!session) {
    void router.push("/");
    return null;
  }

  const { name, email, image, username } = session.user ?? {};

  return (
    <>
      <Head>
        <title>Profile | Create T3 App</title>
        <meta name="description" content="Your GitHub profile" />
        <link rel="icon" href="/favicon.ico" />
      </Head>
      <main className="flex min-h-screen flex-col items-center justify-center bg-gray-100">
        <div className="w-full max-w-sm rounded-xl border border-gray-200 bg-white p-8 shadow-md">
          <h1 className="mb-6 text-center text-2xl font-bold text-gray-800">
            GitHub Profile
          </h1>

          {/* Avatar */}
          {image && (
            <div className="mb-4 flex justify-center">
              <Image
                src={image}
                alt={name ?? "GitHub avatar"}
                width={80}
                height={80}
                className="rounded-full ring-2 ring-gray-300"
              />
            </div>
          )}

          {/* Profile fields */}
          <dl className="mb-6 space-y-2 text-sm text-gray-700">
            {name && (
              <div className="flex justify-between">
                <dt className="font-medium text-gray-500">Name</dt>
                <dd>{name}</dd>
              </div>
            )}
            {username && (
              <div className="flex justify-between">
                <dt className="font-medium text-gray-500">Username</dt>
                <dd>
                  <a
                    href={`https://github.com/${username}`}
                    target="_blank"
                    rel="noreferrer"
                    className="text-violet-600 underline decoration-dotted underline-offset-2 hover:text-violet-800"
                  >
                    @{username}
                  </a>
                </dd>
              </div>
            )}
            {email && (
              <div className="flex justify-between">
                <dt className="font-medium text-gray-500">Email</dt>
                <dd>{email}</dd>
              </div>
            )}
            {/* tRPC context verification */}
            {profile && (
              <div className="flex justify-between">
                <dt className="font-medium text-gray-500">Session ID</dt>
                <dd className="truncate font-mono text-xs text-gray-400">
                  {profile.id}
                </dd>
              </div>
            )}
          </dl>

          <button
            onClick={() => signOut({ callbackUrl: "/" })}
            className="w-full rounded-md border-2 border-red-400 px-4 py-2 text-sm font-medium text-red-500 transition hover:bg-red-50"
          >
            Sign out
          </button>
        </div>
      </main>
    </>
  );
};

export default Profile;

